-- Utility functions that don't depend on other entities
-- Detects if running in local Supabase CLI environment
-- by checking if JWT secret matches the known hardcoded local value.
-- Returns true only for exact match; defaults to false (production-safe).
CREATE OR REPLACE FUNCTION pgflow.is_local () returns BOOLEAN language sql stable parallel safe
SET
  search_path = '' AS $$
  select coalesce(
    current_setting('app.settings.jwt_secret', true)
      = 'super-secret-jwt-token-with-at-least-32-characters-long',
    false
  )
$$;


CREATE OR REPLACE FUNCTION pgflow.is_valid_slug (slug TEXT) returns BOOLEAN language plpgsql immutable
SET
  search_path = '' AS $$
begin
    return
      slug is not null
      and slug <> ''
      and length(slug) <= 128
      and slug ~ '^[a-zA-Z_][a-zA-Z0-9_]*$'
      and slug NOT IN ('run'); -- reserved words
end;
$$;


CREATE OR REPLACE FUNCTION pgflow.calculate_retry_delay (base_delay NUMERIC, attempts_count INT) returns INT language sql immutable parallel safe
SET
  search_path = '' AS $$
  select floor(base_delay * power(2, attempts_count))::int
$$;


