-- Track Worker Function
-- Registers an edge function for monitoring by ensure_workers() cron
CREATE OR REPLACE FUNCTION pgflow.track_worker_function (function_name TEXT) returns void language sql AS $$
  insert into pgflow.worker_functions (function_name, updated_at)
  values (track_worker_function.function_name, clock_timestamp())
  on conflict (function_name)
  do update set
    updated_at = clock_timestamp();
$$;


COMMENT ON function pgflow.track_worker_function (TEXT) IS 'Registers an edge function for monitoring. Called by workers on startup.';


