-- ============================================================================
-- Runtime State Tables
-- Runs table - tracks flow execution instances
CREATE TABLE pgflow.runs (
  run_id UUID PRIMARY KEY NOT NULL DEFAULT gen_random_uuid(),
  flow_slug TEXT NOT NULL REFERENCES pgflow.flows (flow_slug), -- denormalized
  status TEXT NOT NULL DEFAULT 'started',
  input JSONB NOT NULL,
  output JSONB,
  remaining_steps INT NOT NULL DEFAULT 0 CHECK (remaining_steps >= 0),
  started_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  completed_at TIMESTAMPTZ,
  failed_at TIMESTAMPTZ,
  CONSTRAINT completed_at_or_failed_at CHECK (
    NOT (
      completed_at IS NOT NULL
      AND failed_at IS NOT NULL
    )
  ),
  CONSTRAINT completed_at_is_after_started_at CHECK (
    completed_at IS NULL
    OR completed_at >= started_at
  ),
  CONSTRAINT failed_at_is_after_started_at CHECK (
    failed_at IS NULL
    OR failed_at >= started_at
  ),
  CONSTRAINT status_is_valid CHECK (status IN ('started', 'failed', 'completed'))
);


CREATE INDEX if NOT EXISTS idx_runs_flow_slug ON pgflow.runs (flow_slug);


CREATE INDEX if NOT EXISTS idx_runs_status ON pgflow.runs (status);


-- Step states table - tracks the state of individual steps within a run
CREATE TABLE pgflow.step_states (
  flow_slug TEXT NOT NULL REFERENCES pgflow.flows (flow_slug),
  run_id UUID NOT NULL REFERENCES pgflow.runs (run_id),
  step_slug TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'created',
  remaining_tasks INT NULL, -- NULL = not started, >0 = active countdown
  initial_tasks INT NULL CHECK (
    initial_tasks IS NULL
    OR initial_tasks >= 0
  ),
  remaining_deps INT NOT NULL DEFAULT 0 CHECK (remaining_deps >= 0),
  output JSONB, -- Step output: stored atomically with status=completed transition
  error_message TEXT,
  skip_reason TEXT, -- Why step was skipped: condition_unmet, handler_failed, dependency_skipped
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  started_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ,
  failed_at TIMESTAMPTZ,
  skipped_at TIMESTAMPTZ,
  PRIMARY KEY (run_id, step_slug),
  FOREIGN key (flow_slug, step_slug) REFERENCES pgflow.steps (flow_slug, step_slug),
  CONSTRAINT status_is_valid CHECK (status IN ('created', 'started', 'completed', 'failed', 'skipped')),
  CONSTRAINT status_and_remaining_tasks_match CHECK (
    status != 'completed'
    OR remaining_tasks = 0
  ),
  -- Add constraint to ensure remaining_tasks is only set when step has started
  CONSTRAINT remaining_tasks_state_consistency CHECK (
    remaining_tasks IS NULL
    OR status NOT IN ('created', 'skipped')
  ),
  CONSTRAINT initial_tasks_known_when_started CHECK (
    status != 'started'
    OR initial_tasks IS NOT NULL
  ),
  -- Output is only allowed for completed steps (or NULL for steps that haven't completed)
  -- Note: allows status=completed with output=NULL for single steps that return NULL
  CONSTRAINT output_only_for_completed_or_null CHECK (
    output IS NULL
    OR status = 'completed'
  ),
  -- skip_reason is required for skipped status and forbidden for other statuses
  CONSTRAINT skip_reason_matches_status CHECK (
    (
      status = 'skipped'
      AND skip_reason IS NOT NULL
    )
    OR (
      status != 'skipped'
      AND skip_reason IS NULL
    )
  ),
  CONSTRAINT completed_at_or_failed_at_or_skipped_at CHECK (
    (
      CASE
        WHEN completed_at IS NOT NULL THEN 1
        ELSE 0
      END + CASE
        WHEN failed_at IS NOT NULL THEN 1
        ELSE 0
      END + CASE
        WHEN skipped_at IS NOT NULL THEN 1
        ELSE 0
      END
    ) <= 1
  ),
  CONSTRAINT started_at_is_after_created_at CHECK (
    started_at IS NULL
    OR started_at >= created_at
  ),
  CONSTRAINT completed_at_is_after_started_at CHECK (
    completed_at IS NULL
    OR completed_at >= started_at
  ),
  CONSTRAINT failed_at_is_after_started_at CHECK (
    failed_at IS NULL
    OR failed_at >= started_at
  ),
  CONSTRAINT skipped_at_is_after_created_at CHECK (
    skipped_at IS NULL
    OR skipped_at >= created_at
  )
);


CREATE INDEX if NOT EXISTS idx_step_states_ready ON pgflow.step_states (run_id, status, remaining_deps)
WHERE
  status = 'created'
  AND remaining_deps = 0;


CREATE INDEX if NOT EXISTS idx_step_states_failed ON pgflow.step_states (run_id, step_slug)
WHERE
  status = 'failed';


CREATE INDEX if NOT EXISTS idx_step_states_skipped ON pgflow.step_states (run_id, step_slug)
WHERE
  status = 'skipped';


CREATE INDEX if NOT EXISTS idx_step_states_flow_slug ON pgflow.step_states (flow_slug);


CREATE INDEX if NOT EXISTS idx_step_states_run_id ON pgflow.step_states (run_id);


-- Step tasks table - tracks units of work for step
CREATE TABLE pgflow.step_tasks (
  flow_slug TEXT NOT NULL REFERENCES pgflow.flows (flow_slug),
  run_id UUID NOT NULL REFERENCES pgflow.runs (run_id),
  step_slug TEXT NOT NULL,
  message_id BIGINT,
  task_index INT NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'queued',
  attempts_count INT NOT NULL DEFAULT 0,
  error_message TEXT,
  output JSONB,
  queued_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  started_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ,
  failed_at TIMESTAMPTZ,
  last_worker_id UUID REFERENCES pgflow.workers (worker_id) ON DELETE SET NULL,
  -- Requeue tracking columns
  requeued_count INT NOT NULL DEFAULT 0,
  last_requeued_at TIMESTAMPTZ,
  permanently_stalled_at TIMESTAMPTZ,
  CONSTRAINT step_tasks_pkey PRIMARY KEY (run_id, step_slug, task_index),
  FOREIGN key (run_id, step_slug) REFERENCES pgflow.step_states (run_id, step_slug),
  CONSTRAINT valid_status CHECK (status IN ('queued', 'started', 'completed', 'failed')),
  CONSTRAINT output_valid_only_for_completed CHECK (
    output IS NULL
    OR status IN ('completed', 'failed')
  ),
  CONSTRAINT attempts_count_nonnegative CHECK (attempts_count >= 0),
  CONSTRAINT completed_at_or_failed_at CHECK (
    NOT (
      completed_at IS NOT NULL
      AND failed_at IS NOT NULL
    )
  ),
  CONSTRAINT completed_at_is_after_queued_at CHECK (
    completed_at IS NULL
    OR completed_at >= queued_at
  ),
  CONSTRAINT failed_at_is_after_queued_at CHECK (
    failed_at IS NULL
    OR failed_at >= queued_at
  ),
  CONSTRAINT started_at_is_after_queued_at CHECK (
    started_at IS NULL
    OR started_at >= queued_at
  ),
  CONSTRAINT completed_at_is_after_started_at CHECK (
    completed_at IS NULL
    OR started_at IS NULL
    OR completed_at >= started_at
  ),
  CONSTRAINT failed_at_is_after_started_at CHECK (
    failed_at IS NULL
    OR started_at IS NULL
    OR failed_at >= started_at
  )
);


CREATE INDEX if NOT EXISTS idx_step_tasks_message_id ON pgflow.step_tasks (message_id);


CREATE INDEX if NOT EXISTS idx_step_tasks_queued ON pgflow.step_tasks (run_id, step_slug)
WHERE
  status = 'queued';


CREATE INDEX if NOT EXISTS idx_step_tasks_completed ON pgflow.step_tasks (run_id, step_slug)
WHERE
  status = 'completed';


CREATE INDEX if NOT EXISTS idx_step_tasks_failed ON pgflow.step_tasks (run_id, step_slug)
WHERE
  status = 'failed';


CREATE INDEX if NOT EXISTS idx_step_tasks_flow_run_step ON pgflow.step_tasks (flow_slug, run_id, step_slug);


-- New indexes for refactored polling behavior
CREATE INDEX if NOT EXISTS idx_step_tasks_started ON pgflow.step_tasks (started_at)
WHERE
  status = 'started';


CREATE INDEX if NOT EXISTS idx_step_tasks_queued_msg ON pgflow.step_tasks (message_id)
WHERE
  status = 'queued';


CREATE INDEX if NOT EXISTS idx_step_tasks_last_worker ON pgflow.step_tasks (last_worker_id)
WHERE
  status = 'started';


-- ============================================================================
-- Source: 0061_function_setup_ensure_workers_cron.sql
-- ============================================================================
-- Setup Ensure Workers Cron
-- Sets up cron jobs for worker management: ensure_workers (configurable interval) and cleanup_logs (hourly)
CREATE OR REPLACE FUNCTION pgflow.setup_ensure_workers_cron (cron_interval TEXT DEFAULT '1 second') returns TEXT language plpgsql security definer
SET
  search_path = pgflow,
  pg_temp AS $$
declare
  ensure_workers_job_id bigint;
  cleanup_job_id bigint;
begin
  IF to_regprocedure('cron.schedule(text,text,text)') IS NULL THEN
    RETURN 'pg_cron is not available in this database; skipped pgflow worker cron setup';
  END IF;

  -- Remove existing jobs if they exist (ignore errors if not found)
  begin
    perform cron.unschedule('pgflow_ensure_workers');
  exception when others then
    -- Job doesn't exist, continue
  end;

  begin
    perform cron.unschedule('pgflow_cleanup_logs');
  exception when others then
    -- Job doesn't exist, continue
  end;

  -- Schedule ensure_workers job with the specified interval
  ensure_workers_job_id := cron.schedule(
    job_name => 'pgflow_ensure_workers',
    schedule => setup_ensure_workers_cron.cron_interval,
    command => 'select pgflow.ensure_workers()'
  );

  -- Schedule cleanup job to run hourly
  cleanup_job_id := cron.schedule(
    job_name => 'pgflow_cleanup_logs',
    schedule => '0 * * * *',
    command => 'select pgflow.cleanup_ensure_workers_logs()'
  );

  return format(
    'Scheduled pgflow_ensure_workers (every %s, job_id=%s) and pgflow_cleanup_logs (hourly, job_id=%s)',
    setup_ensure_workers_cron.cron_interval,
    ensure_workers_job_id,
    cleanup_job_id
  );
end;
$$;


COMMENT ON function pgflow.setup_ensure_workers_cron (TEXT) IS 'Sets up cron jobs for worker management.
Schedules pgflow_ensure_workers at the specified cron_interval (default: 1 second) to keep workers running.
Schedules pgflow_cleanup_logs hourly to clean up old cron job logs.
Replaces existing jobs if they exist (idempotent).
Returns a skipped message when pg_cron is configured in another database.
Returns a confirmation message with job IDs.';


-- ============================================================================
-- Source: 0062_function_requeue_stalled_tasks.sql
-- ============================================================================
-- Requeue stalled tasks that have been in 'started' status longer than their timeout + 30s buffer
-- This handles tasks that got stuck when workers crashed without completing them
CREATE OR REPLACE FUNCTION pgflow.requeue_stalled_tasks () returns INT language plpgsql security definer
SET
  search_path = '' AS $$
declare
  result_count int := 0;
  max_requeues constant int := 3;
begin
  -- Find and requeue stalled tasks (where started_at > timeout + 30s buffer)
  -- Tasks with requeued_count >= max_requeues will have their message archived
  -- but status left as 'started' for easy identification via requeued_count column
  with stalled_tasks as (
    select
      st.run_id,
      st.step_slug,
      st.task_index,
      st.message_id,
      r.flow_slug,
      st.requeued_count,
      f.opt_timeout
    from pgflow.step_tasks st
    join pgflow.runs r on r.run_id = st.run_id
    join pgflow.flows f on f.flow_slug = r.flow_slug
    where st.status = 'started'
      and st.permanently_stalled_at is null
      and st.started_at < now() - (f.opt_timeout * interval '1 second') - interval '30 seconds'
    for update of st skip locked
  ),
  -- Separate tasks that can be requeued from those that exceeded max requeues
  to_requeue as (
    select * from stalled_tasks where requeued_count < max_requeues
  ),
  to_archive as (
    select * from stalled_tasks where requeued_count >= max_requeues
  ),
  -- Update tasks that will be requeued
  requeued as (
    update pgflow.step_tasks st
    set
      status = 'queued',
      started_at = null,
      last_worker_id = null,
      requeued_count = st.requeued_count + 1,
      last_requeued_at = now()
    from to_requeue tr
    where st.run_id = tr.run_id
      and st.step_slug = tr.step_slug
      and st.task_index = tr.task_index
    returning tr.flow_slug as queue_name, tr.message_id
  ),
  -- Make requeued messages visible immediately (batched per queue)
  visibility_reset as (
    select pgflow.set_vt_batch(
      r.queue_name,
      array_agg(r.message_id),
      array_agg(0)  -- all offsets are 0 (immediate visibility)
    )
    from requeued r
    where r.message_id is not null
    group by r.queue_name
  ),
  -- Mark tasks as permanently stalled before archiving
  mark_permanently_stalled as (
    update pgflow.step_tasks st
    set permanently_stalled_at = now()
    from to_archive ta
    where st.run_id = ta.run_id
      and st.step_slug = ta.step_slug
      and st.task_index = ta.task_index
    returning st.run_id
  ),
  -- Archive messages for tasks that exceeded max requeues (batched per queue)
  archived as (
    select pgmq.archive(ta.flow_slug, array_agg(ta.message_id))
    from to_archive ta
    where ta.message_id is not null
    group by ta.flow_slug
  ),
  -- Force execution of visibility_reset CTE
  _vr as (select count(*) from visibility_reset),
  -- Force execution of mark_permanently_stalled CTE
  _mps as (select count(*) from mark_permanently_stalled),
  -- Force execution of archived CTE
  _ar as (select count(*) from archived)
  select count(*) into result_count
  from requeued, _vr, _mps, _ar;

  return result_count;
end;
$$;


-- ============================================================================
-- Source: 0063_function_setup_requeue_stalled_tasks_cron.sql
-- ============================================================================
-- Cron setup function for automatic requeue monitoring
CREATE OR REPLACE FUNCTION pgflow.setup_requeue_stalled_tasks_cron (cron_interval TEXT DEFAULT '15 seconds') returns TEXT language plpgsql security definer
SET
  search_path = pgflow,
  pg_temp AS $$
declare
  job_id bigint;
begin
  IF to_regprocedure('cron.schedule(text,text,text)') IS NULL THEN
    RETURN 'pg_cron is not available in this database; skipped pgflow stalled-task cron setup';
  END IF;

  -- Remove existing job if any
  begin
    perform cron.unschedule('pgflow_requeue_stalled_tasks');
  exception
    when others then null;
  end;

  -- Schedule the new job
  job_id := cron.schedule(
    job_name => 'pgflow_requeue_stalled_tasks',
    schedule => setup_requeue_stalled_tasks_cron.cron_interval,
    command => 'select pgflow.requeue_stalled_tasks()'
  );

  return format('Scheduled pgflow_requeue_stalled_tasks (every %s, job_id=%s)',
    setup_requeue_stalled_tasks_cron.cron_interval, job_id);
end;
$$;


COMMENT ON function pgflow.setup_requeue_stalled_tasks_cron (TEXT) IS 'Sets up cron job to automatically requeue stalled tasks.
Schedules pgflow_requeue_stalled_tasks at the specified cron_interval (default: 15 seconds).
Replaces existing job if it exists (idempotent).
Returns a skipped message when pg_cron is configured in another database.
Returns a confirmation message with job ID.';


-- Automatically set up the cron job when migration runs
SELECT
  pgflow.setup_requeue_stalled_tasks_cron ();


